  "contents": [{
    "parts": [{
      "text": "You are a creative director for Instagram reels. Your job is to do ALL of the following in a SINGLE response as valid JSON only:

1. Understand the song concept from the lyrics
2. Pick the best avatar(s) from the list provided
3. Define clothes and background for the scene
4. Break down the reel into 4-5 shots with prompts

INPUT DATA:
Song Lyrics/Transcription: {{ $json.transcription }}
Reel Type: {{ $json.reelType }}
Timing: {{ $json.timing }}
Optional Concept Hint: {{ $json.conceptInput }}

AVAILABLE AVATARS FOR THIS ACCOUNT:
Avatar 1 URL: {{ $json.avatar1Url }}
Avatar 2 URL: {{ $json.avatar2Url }}
Avatar 3 URL: {{ $json.avatar3Url }}

Return ONLY this JSON structure, no markdown, no explanation:
{
  "song_concept": "2-3 sentence summary of the song's theme and mood",
  "selected_avatars": [
    { "avatar_url": "URL of avatar chosen", "role": "why this avatar fits the concept" }
  ],
  "clothes": "Detailed clothing description for the avatar(s) that fits the song mood",
  "background": "Detailed background/setting description that fits the song mood",
  "nanobana_reference_prompt": "Full prompt to generate the first reference image showing all selected avatars together with the defined clothes and background. Be very detailed.",
  "shots": [
    {
      "shot_number": 1,
      "shot_name": "short_name_no_spaces",
      "description": "What happens in this shot",
      "image_generation_prompt": "Detailed fal.ai prompt for this shot, referencing the clothes and background, maintaining avatar consistency",
      "camera_motion": "e.g. slow zoom in, pan left, static shot, dolly forward",
      "duration_seconds": 3
    }
  ]
}"
    }]
  }]
}

parameters.jsCode:
// Get raw Gemini
const rawText = $input.first().json.content.parts[0].text;

if (!rawText) {
  throw new Error("Gemini returned empty text");
}

// Remove markdown fences if present
let cleaned = rawText
  .replace(/```json/gi, "")
  .replace(/```/g, "")
  .trim();

// Extract JSON safely
const match = cleaned.match(/\{[\s\S]*\}/);

if (!match) {
  throw new Error("No valid JSON found in Gemini response");
}

cleaned = match[0];

let parsed;

try {
  parsed = JSON.parse(cleaned);
} catch (err) {
  throw new Error("Invalid JSON from Gemini: " + cleaned.substring(0, 300));
}

// Get previous workflow context
const ctx = $node["7. Merge Avatar URLs + All Data"].json;

// Return structured data for your pipeline
return [{
  json: {
    reelNumber: ctx.reelNumber,
    accountToPost: ctx.accountToPost,
    reelType: ctx.reelType,
    timing: ctx.timing,
    songLink: ctx.songLink,

    lyricalSubtext: parsed.lyrical_subtext || "",
    colorPalette: parsed.color_palette || "",
    identityAnchor: parsed.identity_anchor || "",
    outfitStyling: parsed.styling?.outfit || "",
    lightingStyling: parsed.styling?.lighting || "",
    reference_image_prompt:parsed.reference_image_prompt || "",
    shots: parsed.shots || [],
    totalShots: parsed.shots?.length || 0
  }
}];

const data = $input.first().json;

let avatarUrls = [];

// If Gemini returned selectedAvatars
if (data.selectedAvatars && data.selectedAvatars.length) {
  avatarUrls = data.selectedAvatars
    .map(a => a.avatar_url)
    .filter(u => u && u.trim() !== "");
} 
// Otherwise fallback to account avatars
else {
  const accountData = $node["6. Get Account Avatar URLs"].json;
  avatarUrls = [
    accountData.avatar1,
    accountData.avatar2,
    accountData.avatar3
  ].filter(u => u && u.trim() !== "");
}

return [{
  json: {
    ...data,
    avatarUrlsForNanobana: avatarUrls,
    avatarUrlsString: avatarUrls.join(", ")
  }
}];

const ctx = $node["10. Prepare Nanobana Input"].json;

return [{
  json: ctx,
  binary: $input.first().binary
}];

