let parentId;

// Try getting searched folder
const searchNode = $node["Search parent Reel"].json;

if (searchNode && searchNode.id) {
  parentId = searchNode.id;
} else {
  const createdNode = $node["Create Reelfolder"].json;

  if (!createdNode || !createdNode.id) {
    throw new Error("Parent folder not found and not created.");
  }

  parentId = createdNode.id;
}

return [{
  json: {
    parentFolderId: parentId
  }
}];

let ReelId;

// Get search results safely
const searchItems = $node["Reel Folder Exists"].json;

if (searchItems && searchItems.id) {
  ReelId = searchItems.id;
} else {
  const createdItems = $node["Create Review_images Folder"].json;

  if (!createdItems || !createdItems.id) {
    throw new Error("Reelfolder not found and not created.");
  }

  ReelId = createdItems.id;
}

return [{
  json: {
    ReelFolderId: ReelId
  }
}];

const data = $input.first().json;

// Build identity description
const identity = data.identityAnchor || "";

// Build styling
const outfit = data.outfitStyling || "";
const lighting = data.lightingStyling || "";
const palette = data.colorPalette || "";

// Construct strong identity-locked prompt
const referencePrompt = `
Maintain exact facial structure
No beautification. No alteration of facial proportions.
Preserve realistic pores and micro skin details.

Outfit: ${outfit}

Lighting: ${lighting}

Color grading palette: ${palette}

Shot on ARRI Alexa, 35mm lens, sharp focus, professional film lighting, shallow depth of field.
`;

// Return updated JSON
return [{
  json: {
    ...data,
    nanobanaReferencePrompt: referencePrompt.trim()
  }
}];

// 1. Get the raw string from your specific node
// Replace '2. Extract Reel Data' with the exact name if different
const rawList = $node["2. Extract Reel Data1"].json["avtarList"] || "";

// 2. Clean the list: split by comma, trim whitespace, and remove empty values
const targetAvatars = rawList.split(',')
  .map(name => name.trim())
  .filter(name => name.length > 0);

// 3. Get all the input items (the list of image rows you provided)
const allRows = items.map(item => item.json);

// 4. Group data by Avatar Name
const grouped = {};

allRows.forEach(row => {
  const name = row["Avatar Name"];

  // Only process if this name exists in our target list
  if (targetAvatars.includes(name)) {
    if (!grouped[name]) {
      grouped[name] = {
        "Avatar Name": name,
        "Avatar Id": row["Avatar Id"],
        "Images": []
      };
    }

    // Construct the Google Drive download link
    const downloadLink = `https://drive.google.com/uc?export=download&id=${row["Image Id"]}`;

    grouped[name].Images.push({
      "Image Name": row["Image name"],
      "Download Link": downloadLink
    });
  }
});

// 5. Convert the grouped object back into an array for n8n output
return Object.values(grouped);

