let concept;

// Check IF node result
const ifTrueItems = $items("checking if concept is present", 0, 0);

if (ifTrueItems.length > 0) {
  // TRUE branch → concept already exists
  concept = ifTrueItems[0].json.conceptInput;
} else {
  // FALSE branch → take Gemini generated concept
  const gemini = $items("Output the concept", 0, 0);
  concept = gemini[0].json.content.parts[0].text;
}

return [
  {
    json: {
      conceptInput: concept
    }
  }
];
